// +esm 的 interval-arithmetic 依赖当前在 jsDelivr 失效；使用包内自包含 UMD
const el = document.getElementById('plot'); el.style.height = '400px'; el.textContent = 'Loading plot…';
const script = document.createElement('script'); script.src = 'https://cdn.jsdelivr.net/npm/function-plot@1.25.4/dist/function-plot.js';
await new Promise((ok, fail) => { script.onload = ok; script.onerror = fail; document.head.appendChild(script); });
const functionPlot = globalThis.functionPlot; delete globalThis.functionPlot; script.remove(); el.textContent = '';
const width = el.clientWidth || 640;
const chart = functionPlot({ ...data, target: el, width, height: 400 });

